import sys

def check(s):
    cnt = [0] * 26
    for i in s:
        cnt[ord(i) - ord('a')] += 1
    odd = 0
    for i in cnt:
        if i % 2 == 1:
            odd += 1
    if odd <= 1:
        return True
    else:
        return False

t = int(sys.stdin.readline())
for _ in range(t):
