        cnt = [0] * 26
        for i in s:
            cnt[ord(i) - ord('a')] += 1
        ans = ''
        odd = []
        for i in range(26):
            if cnt[i] % 2 == 1:
                odd.append(chr(i + ord('a')))
                cnt[i] -= 1
        for i in range(26):
